using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly Lock _lock = new();
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[] _categoryLabels = [];

    public bool IsModelTrained => _model is not null;

    public TicketModelService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public EvaluationResponse TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Combine text features and build the pipeline
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // Train on full data (small dataset — cross-validation used for metrics)
        var model = pipeline.Fit(dataView);

        // Cross-validate to get realistic metrics on this small dataset
        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        var metrics = cvResults
            .OrderByDescending(r => r.Metrics.MicroAccuracy)
            .First().Metrics;

        // Persist model and swap in atomically
        _mlContext.Model.Save(model, dataView.Schema, _modelPath);
        SetModel(model, dataView);

        return BuildEvaluationResponse(metrics);
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        lock (_lock)
        {
            if (_predictionEngine is null)
                throw new InvalidOperationException("Model has not been trained yet.");

            var input = new TicketData
            {
                Subject = request.Subject,
                Description = request.Description,
                Priority = request.Priority
            };

            var prediction = _predictionEngine.Predict(input);

            var confidence = new Dictionary<string, float>();
            for (var i = 0; i < _categoryLabels.Length; i++)
                confidence[_categoryLabels[i]] = prediction.Score[i];

            return new PredictionResponse(prediction.PredictedCategory, confidence);
        }
    }

    public void LoadModelIfExists()
    {
        if (!File.Exists(_modelPath))
            return;

        var model = _mlContext.Model.Load(_modelPath, out _);
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        SetModel(model, dataView);
    }

    private void SetModel(ITransformer model, IDataView dataView)
    {
        lock (_lock)
        {
            _model = model;
            _predictionEngine = _mlContext.Model
                .CreatePredictionEngine<TicketData, TicketPrediction>(model);

            // Extract label ordering so we can map Score[] indices to names
            var labelCol = _model.Transform(dataView).Schema["Label"];
            var slotNames = new VBuffer<ReadOnlyMemory<char>>();
            labelCol.GetKeyValues(ref slotNames);
            _categoryLabels = slotNames.DenseValues()
                .Select(v => v.ToString()).ToArray();
        }
    }

    private static EvaluationResponse BuildEvaluationResponse(
        MulticlassClassificationMetrics metrics)
    {
        return new EvaluationResponse(
            MicroAccuracy: (float)metrics.MicroAccuracy,
            MacroAccuracy: (float)metrics.MacroAccuracy,
            LogLoss: (float)metrics.LogLoss,
            LogLossReduction: (float)metrics.LogLossReduction,
            ConfusionMatrix: metrics.ConfusionMatrix.GetFormattedConfusionTable());
    }
}

