using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController(TicketModelService modelService) : ControllerBase
{
    /// <summary>Trains the model on the CSV data and returns evaluation metrics.</summary>
    [HttpPost("train")]
    public ActionResult<TrainResponse> Train()
    {
        var metrics = modelService.TrainAndEvaluate();
        return Ok(new TrainResponse("Model trained successfully", metrics));
    }

    /// <summary>Predicts the category for a support ticket.</summary>
    [HttpPost("predict")]
    public ActionResult<PredictionResponse> Predict([FromBody] TicketRequest request)
    {
        if (!modelService.IsModelTrained)
            return BadRequest(new { error = "Model not trained. Call POST /api/ticketclassifier/train first." });

        if (request.Priority is < 1 or > 3)
            return BadRequest(new { error = "Priority must be between 1 and 3." });

        var prediction = modelService.Predict(request);
        return Ok(prediction);
    }
}

